('additional-maths:5-2-sine-and-cosine-rules:mcq:fa0b93e9', 'additional-maths', 'additional-maths:5-2-sine-and-cosine-rules', '5.2 Sine and Cosine Rules', 'mcq', 'mcq', 1, '{"question": "You are given two sides of a triangle and the angle between them (SAS). Which rule finds the third side?", "options": ["The cosine rule", "The sine rule", "The area formula", "Pythagoras'' theorem"]}'::jsonb, '{"answer": 0, "explain": "SAS has no side paired with its opposite angle, so the sine rule cannot start. Use \\( a^2 = b^2 + c^2 - 2bc\\cos A \\)."}'::jsonb),
('additional-maths:5-2-sine-and-cosine-rules:mcq:3fbc4638', 'additional-maths', 'additional-maths:5-2-sine-and-cosine-rules', '5.2 Sine and Cosine Rules', 'mcq', 'mcq', 1, '{"question": "You know all three sides of a triangle (SSS) and want an angle. Which rule do you use?", "options": ["The cosine rule, rearranged for the angle", "The sine rule", "The area formula", "You cannot find an angle from three sides"]}'::jsonb, '{"answer": 0, "explain": "Use \\( \\cos A = \\dfrac{b^2 + c^2 - a^2}{2bc} \\); the sine rule needs an angle to start, which SSS does not give."}'::jsonb),
('additional-maths:5-2-sine-and-cosine-rules:mcq:eeca7231', 'additional-maths', 'additional-maths:5-2-sine-and-cosine-rules', '5.2 Sine and Cosine Rules', 'mcq', 'mcq', 1, '{"question": "Complete the sine rule: \\( \\dfrac{a}{\\sin A} = \\ \\square \\).", "options": ["\\( \\dfrac{b}{\\sin B} \\)", "\\( \\dfrac{\\sin B}{b} \\)", "\\( \\dfrac{b}{\\cos B} \\)", "\\( b\\sin B \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( \\dfrac{a}{\\sin A} = \\dfrac{b}{\\sin B} = \\dfrac{c}{\\sin C} \\); each side sits over the sine of its opposite angle."}'::jsonb),
('additional-maths:5-2-sine-and-cosine-rules:mcq:d52af41d', 'additional-maths', 'additional-maths:5-2-sine-and-cosine-rules', '5.2 Sine and Cosine Rules', 'mcq', 'mcq', 1, '{"question": "Find side \\( a \\) when \\( b = 5,\\ c = 8 \\) and the included angle \\( A = 60^\\circ \\).", "options": ["\\( 7 \\)", "\\( 11.4 \\)", "\\( 3 \\)", "\\( 9.4 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( a^2 = 25 + 64 - 2(5)(8)\\cos 60^\\circ = 89 - 40 = 49 \\), so \\( a = 7 \\). (Using \\( +40 \\) gives the wrong \\( \\sqrt{129} = 11.4 \\).)"}'::jsonb),
('additional-maths:5-2-sine-and-cosine-rules:mcq:1157244e', 'additional-maths', 'additional-maths:5-2-sine-and-cosine-rules', '5.2 Sine and Cosine Rules', 'mcq', 'mcq', 1, '{"question": "A student writes the cosine rule as \\( a^2 = b^2 + c^2 + 2bc\\cos A \\). What is wrong?", "options": ["The last term should be subtracted: \\( -2bc\\cos A \\)", "Nothing is wrong — squared terms are always added together", "It should be \\( +2bc\\sin A \\)", "\\( a^2 \\) should be \\( 2a^2 \\)"]}'::jsonb, '{"answer": 0, "explain": "The cosine rule subtracts: \\( a^2 = b^2 + c^2 - 2bc\\cos A \\). The wrong sign is the most common slip."}'::jsonb),
('additional-maths:5-2-sine-and-cosine-rules:mcq:8423c7dd', 'additional-maths', 'additional-maths:5-2-sine-and-cosine-rules', '5.2 Sine and Cosine Rules', 'mcq', 'mcq', 1, '{"question": "Find angle \\( A \\) (opposite the side of length 7) in a triangle with sides \\( a = 7,\\ b = 8,\\ c = 9 \\).", "options": ["\\( 48.2^\\circ \\)", "\\( 58.4^\\circ \\)", "\\( 73.4^\\circ \\)", "\\( 41.8^\\circ \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( \\cos A = \\dfrac{8^2 + 9^2 - 7^2}{2(8)(9)} = \\dfrac{96}{144} = 0.6667 \\), so \\( A = 48.2^\\circ \\)."}'::jsonb),
('additional-maths:5-2-sine-and-cosine-rules:mcq:71b5b9d6', 'additional-maths', 'additional-maths:5-2-sine-and-cosine-rules', '5.2 Sine and Cosine Rules', 'mcq', 'mcq', 1, '{"question": "The sine rule gives \\( \\sin C = 0.8 \\). What are the two possible values of \\( C \\)?", "options": ["\\( 53.1^\\circ \\) and \\( 126.9^\\circ \\)", "\\( 53.1^\\circ \\) only", "\\( 53.1^\\circ \\) and \\( 306.9^\\circ \\)", "\\( 36.9^\\circ \\) and \\( 143.1^\\circ \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( \\sin^{-1}(0.8) = 53.1^\\circ \\); the obtuse partner is \\( 180^\\circ - 53.1^\\circ = 126.9^\\circ \\)."}'::jsonb),
('additional-maths:5-2-sine-and-cosine-rules:mcq:13fe7899', 'additional-maths', 'additional-maths:5-2-sine-and-cosine-rules', '5.2 Sine and Cosine Rules', 'mcq', 'mcq', 1, '{"question": "In a triangle \\( A = 35^\\circ,\\ a = 8,\\ b = 11 \\). Find the OBTUSE possible value of angle \\( B \\).", "options": ["\\( 127.9^\\circ \\)", "\\( 52.1^\\circ \\)", "\\( 55^\\circ \\)", "\\( 180^\\circ - 35^\\circ = 145^\\circ \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( \\sin B = \\dfrac{11\\sin 35^\\circ}{8} = 0.7887 \\); acute \\( 52.1^\\circ \\), obtuse \\( 180^\\circ - 52.1^\\circ = 127.9^\\circ \\)."}'::jsonb),
('additional-maths:5-2-sine-and-cosine-rules:mcq:6aac9446', 'additional-maths', 'additional-maths:5-2-sine-and-cosine-rules', '5.2 Sine and Cosine Rules', 'mcq', 'mcq', 1, '{"question": "Find the area of a triangle with sides \\( 10 \\) cm and \\( 14 \\) cm and an included angle of \\( 30^\\circ \\).", "options": ["\\( 35 \\) cm\\( ^2 \\)", "\\( 70 \\) cm\\( ^2 \\)", "\\( 60.6 \\) cm\\( ^2 \\)", "\\( 17.5 \\) cm\\( ^2 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( \\tfrac{1}{2} \\times 10 \\times 14 \\times \\sin 30^\\circ = 70 \\times 0.5 = 35 \\) cm\\( ^2 \\)."}'::jsonb),
('additional-maths:5-2-sine-and-cosine-rules:mcq:1a77d90f', 'additional-maths', 'additional-maths:5-2-sine-and-cosine-rules', '5.2 Sine and Cosine Rules', 'mcq', 'mcq', 1, '{"question": "In the SSA setup with known angle \\( A \\) and sides \\( a \\) (opposite \\( A \\)) and \\( b \\), two different triangles exist when:", "options": ["\\( b\\sin A < a < b \\)", "\\( a > b \\) always", "\\( a = b \\)", "\\( A > 90^\\circ \\)"]}'::jsonb, '{"answer": 0, "explain": "If \\( a \\) is longer than the height \\( b\\sin A \\) but shorter than \\( b \\), the side reaches the base line in two places — two triangles."}'::jsonb),
('additional-maths:5-2-sine-and-cosine-rules:mcq:973c8c12', 'additional-maths', 'additional-maths:5-2-sine-and-cosine-rules', '5.2 Sine and Cosine Rules', 'mcq', 'mcq', 1, '{"question": "Which is the correct rearrangement of the cosine rule for \\( \\cos A \\)?", "options": ["\\( \\dfrac{b^2 + c^2 - a^2}{2bc} \\)", "\\( \\dfrac{a^2 + b^2 - c^2}{2bc} \\)", "\\( \\dfrac{b^2 + c^2 - a^2}{2ab} \\)", "\\( \\dfrac{a^2 - b^2 - c^2}{2bc} \\)"]}'::jsonb, '{"answer": 0, "explain": "Rearranging \\( a^2 = b^2 + c^2 - 2bc\\cos A \\) gives \\( \\cos A = \\dfrac{b^2 + c^2 - a^2}{2bc} \\) — the \\( a^2 \\) (opposite \\( A \\)) is the one subtracted."}'::jsonb),
('additional-maths:5-2-sine-and-cosine-rules:mcq:f325cc74', 'additional-maths', 'additional-maths:5-2-sine-and-cosine-rules', '5.2 Sine and Cosine Rules', 'mcq', 'mcq', 1, '{"question": "Given two sides and the angle between them, a student tries the sine rule to find the third side. Why does it fail?", "options": ["No side is paired with its opposite angle, so no sine-rule ratio can be formed", "The sine rule only works in right-angled triangles, and this triangle is not right-angled", "The sine rule cannot find sides, only angles", "It does not fail — it works fine"]}'::jsonb, '{"answer": 0, "explain": "The only known angle sits between the two known sides (not opposite a known side), so the sine rule has no complete ratio. SAS needs the cosine rule."}'::jsonb),
('additional-maths:5-2-sine-and-cosine-rules:tf:bf6343b4', 'additional-maths', 'additional-maths:5-2-sine-and-cosine-rules', '5.2 Sine and Cosine Rules', 'tf', 'tf', 1, '{"question": "The sine rule states \\( \\dfrac{a}{\\sin A} = \\dfrac{b}{\\sin B} = \\dfrac{c}{\\sin C} \\)."}'::jsonb, '{"answer": true, "explain": "Correct — each side is divided by the sine of its opposite angle, and the three ratios are equal."}'::jsonb),
('additional-maths:5-2-sine-and-cosine-rules:tf:44867082', 'additional-maths', 'additional-maths:5-2-sine-and-cosine-rules', '5.2 Sine and Cosine Rules', 'tf', 'tf', 1, '{"question": "You use the cosine rule when you know two sides and the angle between them (SAS)."}'::jsonb, '{"answer": true, "explain": "Right — SAS has no side-opposite-angle pair, so the cosine rule \\( a^2 = b^2 + c^2 - 2bc\\cos A \\) is needed."}'::jsonb),
('additional-maths:5-2-sine-and-cosine-rules:tf:52286e2b', 'additional-maths', 'additional-maths:5-2-sine-and-cosine-rules', '5.2 Sine and Cosine Rules', 'tf', 'tf', 1, '{"question": "The formula \\( \\dfrac{1}{2}ab\\sin C \\) works for any angle C in the triangle."}'::jsonb, '{"answer": false, "explain": "C must be the INCLUDED angle — the angle between the two sides \\( a \\) and \\( b \\) you multiply."}'::jsonb),
('additional-maths:5-2-sine-and-cosine-rules:tf:ba610fa2', 'additional-maths', 'additional-maths:5-2-sine-and-cosine-rules', '5.2 Sine and Cosine Rules', 'tf', 'tf', 1, '{"question": "In the cosine rule \\( a^2 = b^2 + c^2 - 2bc\\cos A \\), angle A is the angle opposite side a."}'::jsonb, '{"answer": true, "explain": "Yes — the subtracted side, \\( a \\), is always opposite the angle used, \\( A \\)."}'::jsonb),
('additional-maths:5-2-sine-and-cosine-rules:tf:ce50cd68', 'additional-maths', 'additional-maths:5-2-sine-and-cosine-rules', '5.2 Sine and Cosine Rules', 'tf', 'tf', 1, '{"question": "The sine and cosine rules are printed on the exam formula sheet."}'::jsonb, '{"answer": false, "explain": "Both are MEMORISE formulae; the sheet only provides binomial, binomial-distribution, trapezium and kinematics results."}'::jsonb),
('additional-maths:5-2-sine-and-cosine-rules:tf:f30e0516', 'additional-maths', 'additional-maths:5-2-sine-and-cosine-rules', '5.2 Sine and Cosine Rules', 'tf', 'tf', 1, '{"question": "If \\( \\sin C = 0.5 \\) then C could be \\( 30^\\circ \\) or \\( 150^\\circ \\)."}'::jsonb, '{"answer": true, "explain": "\\( \\sin \\) gives the same value for an angle and its obtuse partner: \\( \\sin 30^\\circ = \\sin 150^\\circ = 0.5 \\)."}'::jsonb),
('additional-maths:5-2-sine-and-cosine-rules:tf:551ade93', 'additional-maths', 'additional-maths:5-2-sine-and-cosine-rules', '5.2 Sine and Cosine Rules', 'tf', 'tf', 1, '{"question": "The ambiguous case of the sine rule arises when you are given two angles and a side (AAS)."}'::jsonb, '{"answer": false, "explain": "It arises in the SSA case — two sides and a NON-included angle. AAS gives a unique triangle."}'::jsonb),
('additional-maths:5-2-sine-and-cosine-rules:tf:0f7191bf', 'additional-maths', 'additional-maths:5-2-sine-and-cosine-rules', '5.2 Sine and Cosine Rules', 'tf', 'tf', 1, '{"question": "In the ambiguous case, the obtuse second solution is always a valid triangle."}'::jsonb, '{"answer": false, "explain": "It is only valid if the known angle plus the obtuse angle stays below \\( 180^\\circ \\); otherwise only the acute triangle exists."}'::jsonb),
('additional-maths:5-2-sine-and-cosine-rules:learn:a8a0619f', 'additional-maths', 'additional-maths:5-2-sine-and-cosine-rules', '5.2 Sine and Cosine Rules', 'learn', 'mcq', 1, '{"readingTitle": "Which rule do you use — sine or cosine?", "reading": "<p>In <strong>any</strong> triangle (not just right-angled ones) the <strong>sine rule</strong> and <strong>cosine rule</strong> connect the sides and angles. We label a triangle so that side \\( a \\) is <strong>opposite</strong> angle \\( A \\), side \\( b \\) opposite \\( B \\), and side \\( c \\) opposite \\( C \\).</p>\n            <svg viewBox=\"0 0 300 210\" width=\"100%\" style=\"max-width:340px;height:auto;display:block;margin:14px auto\" role=\"img\" aria-label=\"Triangle ABC with vertex A bottom-left, B at the top, C bottom-right; side a opposite A, side b opposite B, side c opposite C\">\n              <polygon points=\"40,170 155,40 265,170\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.5\"/>\n              <text x=\"30\" y=\"182\" font-size=\"14\" fill=\"currentColor\">A</text>\n              <text x=\"152\" y=\"32\" font-size=\"14\" fill=\"currentColor\">B</text>\n              <text x=\"272\" y=\"182\" font-size=\"14\" fill=\"currentColor\">C</text>\n              <text x=\"88\" y=\"100\" font-size=\"14\" fill=\"currentColor\" font-style=\"italic\">c</text>\n              <text x=\"220\" y=\"100\" font-size=\"14\" fill=\"currentColor\" font-style=\"italic\">a</text>\n              <text x=\"150\" y=\"188\" font-size=\"14\" fill=\"currentColor\" font-style=\"italic\">b</text>\n            </svg>\n            <p>Choose the rule from what you are <strong>given</strong>:</p>\n            <ul>\n              <li><strong>Two sides and the angle between them (SAS)</strong> → <strong>cosine rule</strong> to find the third side.</li>\n              <li><strong>All three sides (SSS)</strong> → <strong>cosine rule</strong>, rearranged to find an angle.</li>\n              <li><strong>Two angles and a side (ASA / AAS)</strong> → <strong>sine rule</strong>.</li>\n              <li><strong>Two sides and a non-included angle (SSA)</strong> → <strong>sine rule</strong> — but beware the <strong>ambiguous case</strong> (last card).</li>\n            </ul>\n            <p>A quick test for the sine rule: it needs a <em>matching pair</em> — a side and its opposite angle both known. If you have no such pair, reach for the cosine rule.</p>", "question": "You know two sides of a triangle and the angle between them. Which rule finds the third side?", "options": ["The cosine rule", "The sine rule", "Pythagoras'' theorem", "The area formula"]}'::jsonb, '{"answer": 0, "explain": "Two sides and the included angle (SAS) gives no side-and-opposite-angle pair, so the sine rule cannot start — use the cosine rule."}'::jsonb),
('additional-maths:5-2-sine-and-cosine-rules:learn:7ddee120', 'additional-maths', 'additional-maths:5-2-sine-and-cosine-rules', '5.2 Sine and Cosine Rules', 'learn', 'mcq', 1, '{"readingTitle": "How do you use the sine rule to find a side?", "reading": "<p>The <strong>sine rule</strong> is \\[ \\frac{a}{\\sin A} = \\frac{b}{\\sin B} = \\frac{c}{\\sin C}. \\] To find a <strong>side</strong>, keep the sides on top. (To find an <strong>angle</strong> it is easier to flip it: \\( \\frac{\\sin A}{a} = \\frac{\\sin B}{b} = \\frac{\\sin C}{c} \\).)</p>\n            <p><strong>Worked example — find \\( b \\) when \\( A = 40^\\circ,\\ B = 75^\\circ,\\ a = 8 \\) cm:</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. Pick the two ratios you can use: \\( \\dfrac{b}{\\sin B} = \\dfrac{a}{\\sin A} \\).</td></tr>\n              <tr><td>2. Substitute: \\( \\dfrac{b}{\\sin 75^\\circ} = \\dfrac{8}{\\sin 40^\\circ} \\).</td></tr>\n              <tr><td>3. Multiply up: \\( b = \\dfrac{8\\sin 75^\\circ}{\\sin 40^\\circ} \\).</td></tr>\n              <tr><td>4. Evaluate: \\( b = \\dfrac{8 \\times 0.9659}{0.6428} = 12.0 \\) cm (3 s.f.).</td></tr>\n            </table>\n            <p>Always pair a side with the angle <em>opposite</em> it. Keep the calculator in <strong>degrees</strong> — the whole of this qualification is in degrees.</p>", "question": "In a triangle \\( A = 30^\\circ,\\ B = 45^\\circ \\) and side \\( a = 10 \\) cm. Find side \\( b \\).", "options": ["\\( 14.1 \\) cm", "\\( 7.07 \\) cm", "\\( 20 \\) cm", "\\( 5 \\) cm"]}'::jsonb, '{"answer": 0, "explain": "\\( b = \\dfrac{10\\sin 45^\\circ}{\\sin 30^\\circ} = \\dfrac{10 \\times 0.7071}{0.5} = 14.1 \\) cm."}'::jsonb),
('additional-maths:5-2-sine-and-cosine-rules:learn:2e6885e7', 'additional-maths', 'additional-maths:5-2-sine-and-cosine-rules', '5.2 Sine and Cosine Rules', 'learn', 'mcq', 1, '{"readingTitle": "How do you use the cosine rule?", "reading": "<p>The <strong>cosine rule</strong> for a side is \\[ a^2 = b^2 + c^2 - 2bc\\cos A, \\] where \\( A \\) is the angle <strong>between</strong> sides \\( b \\) and \\( c \\). Rearranged to find an angle: \\[ \\cos A = \\frac{b^2 + c^2 - a^2}{2bc}. \\]</p>\n            <p><strong>Worked example (find a side, SAS) — \\( b = 7,\\ c = 9,\\ A = 40^\\circ \\):</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. \\( a^2 = 7^2 + 9^2 - 2 \\times 7 \\times 9 \\times \\cos 40^\\circ \\).</td></tr>\n              <tr><td>2. \\( a^2 = 49 + 81 - 126 \\times 0.7660 = 130 - 96.52 = 33.48 \\).</td></tr>\n              <tr><td>3. \\( a = \\sqrt{33.48} = 5.79 \\) cm (3 s.f.).</td></tr>\n            </table>\n            <p><strong>Worked example (find an angle, SSS) — \\( a = 8,\\ b = 5,\\ c = 7 \\):</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. \\( \\cos A = \\dfrac{5^2 + 7^2 - 8^2}{2 \\times 5 \\times 7} = \\dfrac{25 + 49 - 64}{70} = \\dfrac{10}{70} \\).</td></tr>\n              <tr><td>2. \\( \\cos A = 0.1429 \\), so \\( A = \\cos^{-1}(0.1429) = 81.8^\\circ \\).</td></tr>\n            </table>\n            <p>Watch the sign: the term is <strong>minus</strong> \\( 2bc\\cos A \\). Writing \\( +2bc\\cos A \\) is the most common cosine-rule slip.</p>", "question": "Find side \\( a \\) when \\( b = 6,\\ c = 10 \\) and the included angle \\( A = 60^\\circ \\).", "options": ["\\( 8.72 \\) cm", "\\( 11.7 \\) cm", "\\( 12.3 \\) cm", "\\( 4 \\) cm"]}'::jsonb, '{"answer": 0, "explain": "\\( a^2 = 36 + 100 - 120\\cos 60^\\circ = 136 - 60 = 76 \\), so \\( a = \\sqrt{76} = 8.72 \\) cm. (Using \\( +60 \\) gives the wrong \\( 11.7 \\).)"}'::jsonb),
('additional-maths:5-2-sine-and-cosine-rules:learn:a81d5c11', 'additional-maths', 'additional-maths:5-2-sine-and-cosine-rules', '5.2 Sine and Cosine Rules', 'learn', 'mcq', 1, '{"readingTitle": "How do you find the area of a triangle?", "reading": "<p>When you know <strong>two sides and the angle between them</strong>, the area is \\[ \\text{Area} = \\frac{1}{2}ab\\sin C, \\] where \\( C \\) is the <strong>included</strong> angle (the angle <em>between</em> sides \\( a \\) and \\( b \\)). This is a <strong>memorise</strong> formula.</p>\n            <p><strong>Worked example — \\( a = 8 \\) cm, \\( b = 11 \\) cm, included angle \\( C = 35^\\circ \\):</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. \\( \\text{Area} = \\dfrac{1}{2} \\times 8 \\times 11 \\times \\sin 35^\\circ \\).</td></tr>\n              <tr><td>2. \\( \\text{Area} = 44 \\times 0.5736 = 25.2 \\) cm\\( ^2 \\) (3 s.f.).</td></tr>\n            </table>\n            <p>The angle must be the one <em>between</em> the two sides you use. If you are given the wrong angle, find another (often via the sine or cosine rule) before using the area formula.</p>", "question": "Find the area of a triangle with sides \\( 6 \\) cm and \\( 9 \\) cm and an included angle of \\( 50^\\circ \\).", "options": ["\\( 20.7 \\) cm\\( ^2 \\)", "\\( 27 \\) cm\\( ^2 \\)", "\\( 41.4 \\) cm\\( ^2 \\)", "\\( 24.9 \\) cm\\( ^2 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( \\tfrac{1}{2} \\times 6 \\times 9 \\times \\sin 50^\\circ = 27 \\times 0.7660 = 20.7 \\) cm\\( ^2 \\)."}'::jsonb),
('additional-maths:5-2-sine-and-cosine-rules:learn:3fed61d3', 'additional-maths', 'additional-maths:5-2-sine-and-cosine-rules', '5.2 Sine and Cosine Rules', 'learn', 'mcq', 1, '{"readingTitle": "When does the ambiguous case of the sine rule arise?", "reading": "<p>When you use the sine rule to find an <strong>angle</strong> from two sides and a <strong>non-included</strong> angle (the <strong>SSA</strong> setup), there can be <strong>two</strong> different triangles that fit the information. This is the <strong>ambiguous case</strong>.</p>\n            <p>The reason: \\( \\sin\\theta \\) takes the <em>same</em> value for an acute angle and its obtuse partner. If \\( \\sin C = k \\), then both \\( C = \\sin^{-1} k \\) and \\( C = 180^\\circ - \\sin^{-1} k \\) satisfy it. Your calculator only gives the acute (principal) value — you must consider the obtuse one too.</p>\n            <svg viewBox=\"0 0 320 190\" width=\"100%\" style=\"max-width:360px;height:auto;display:block;margin:14px auto\" role=\"img\" aria-label=\"Vertex A on the left with side AB of length 12 going up to B; side BC of a fixed length swings down to meet the base line at two points, giving an obtuse triangle and an acute triangle\">\n              <line x1=\"30\" y1=\"160\" x2=\"300\" y2=\"160\" stroke=\"currentColor\" stroke-width=\"1.5\"/>\n              <line x1=\"30\" y1=\"160\" x2=\"150\" y2=\"55\" stroke=\"currentColor\" stroke-width=\"2.5\"/>\n              <line x1=\"150\" y1=\"55\" x2=\"110\" y2=\"160\" stroke=\"currentColor\" stroke-width=\"2.5\"/>\n              <line x1=\"150\" y1=\"55\" x2=\"240\" y2=\"160\" stroke=\"currentColor\" stroke-width=\"2.5\"/>\n              <path d=\"M 110 160 A 105 105 0 0 1 240 160\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.2\" stroke-dasharray=\"4 3\"/>\n              <circle cx=\"30\" cy=\"160\" r=\"3.5\" fill=\"currentColor\"/>\n              <circle cx=\"150\" cy=\"55\" r=\"3.5\" fill=\"currentColor\"/>\n              <circle cx=\"110\" cy=\"160\" r=\"3.5\" fill=\"currentColor\"/>\n              <circle cx=\"240\" cy=\"160\" r=\"3.5\" fill=\"currentColor\"/>\n              <text x=\"20\" y=\"176\" font-size=\"13\" fill=\"currentColor\">A</text>\n              <text x=\"150\" y=\"48\" font-size=\"13\" fill=\"currentColor\">B</text>\n              <text x=\"96\" y=\"176\" font-size=\"12\" fill=\"currentColor\">C₁</text>\n              <text x=\"236\" y=\"176\" font-size=\"12\" fill=\"currentColor\">C₂</text>\n              <text x=\"70\" y=\"100\" font-size=\"12\" fill=\"currentColor\" font-style=\"italic\">12</text>\n            </svg>\n            <p>The same side \\( BC \\) reaches the base line at \\( C_1 \\) (giving an <strong>obtuse</strong> angle \\( C \\)) and at \\( C_2 \\) (giving an <strong>acute</strong> angle \\( C \\)) — two valid triangles.</p>\n            <p><strong>Worked example — \\( A = 40^\\circ,\\ a = 6,\\ b = 8 \\), find angle \\( B \\):</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. \\( \\dfrac{\\sin B}{b} = \\dfrac{\\sin A}{a} \\Rightarrow \\sin B = \\dfrac{8\\sin 40^\\circ}{6} = 0.8571 \\).</td></tr>\n              <tr><td>2. Acute value: \\( B = \\sin^{-1}(0.8571) = 59.0^\\circ \\).</td></tr>\n              <tr><td>3. Obtuse partner: \\( B = 180^\\circ - 59.0^\\circ = 121.0^\\circ \\).</td></tr>\n              <tr><td>4. Check both: with \\( A = 40^\\circ \\), each leaves a positive third angle (\\( 81^\\circ \\) or \\( 19^\\circ \\)), so <strong>both</strong> triangles are valid.</td></tr>\n            </table>\n            <p>The second solution is only valid if the known angle plus the obtuse angle stays <strong>below</strong> \\( 180^\\circ \\). It is <em>not</em> valid when the side opposite the known angle is long enough (\\( a \\ge b \\)) — then only one triangle exists.</p>", "question": "The sine rule gives \\( \\sin C = 0.6 \\), and the triangle is known to be obtuse at \\( C \\). What is \\( C \\)?", "options": ["\\( 143.1^\\circ \\)", "\\( 36.9^\\circ \\)", "\\( 53.1^\\circ \\)", "\\( 216.9^\\circ \\)"]}'::jsonb, '{"answer": 0, "explain": "The acute value is \\( \\sin^{-1}(0.6) = 36.9^\\circ \\); the obtuse partner is \\( 180^\\circ - 36.9^\\circ = 143.1^\\circ \\)."}'::jsonb),
('additional-maths:5-2-sine-and-cosine-rules:learn:23025a3a', 'additional-maths', 'additional-maths:5-2-sine-and-cosine-rules', '5.2 Sine and Cosine Rules', 'learn', 'mcq', 1, '{"readingTitle": "Which trig formulae must you memorise?", "reading": "<p>None of this page''s formulae are printed on the exam formula sheet — you must <strong>memorise all three</strong>:</p>\n            <ul>\n              <li><strong>Sine rule:</strong> \\( \\dfrac{a}{\\sin A} = \\dfrac{b}{\\sin B} = \\dfrac{c}{\\sin C} \\).</li>\n              <li><strong>Cosine rule:</strong> \\( a^2 = b^2 + c^2 - 2bc\\cos A \\) (and \\( \\cos A = \\dfrac{b^2+c^2-a^2}{2bc} \\)).</li>\n              <li><strong>Area:</strong> \\( \\dfrac{1}{2}ab\\sin C \\).</li>\n            </ul>\n            <p>The formula sheet only provides the binomial series, the binomial distribution, the trapezium rule and the kinematics relations — the trigonometry rules are your responsibility.</p>\n            <p>Two habits protect marks: keep your calculator in <strong>degrees</strong>, and label the triangle so that each side sits opposite its matching capital-letter angle before you substitute.</p>", "question": "Which of these formulae is printed on the 6993 formula sheet?", "options": ["None — the sine, cosine and area rules must all be memorised", "The sine rule only", "The cosine rule only", "All three are printed on the sheet with the binomial expansion"]}'::jsonb, '{"answer": 0, "explain": "The sine rule, cosine rule and area \\( = \\tfrac{1}{2}ab\\sin C \\) are all MEMORISE formulae; the sheet provides binomial, distribution, trapezium and kinematics results only."}'::jsonb),
('additional-maths:5-2-sine-and-cosine-rules:misc:d6c6149b', 'additional-maths', 'additional-maths:5-2-sine-and-cosine-rules', '5.2 Sine and Cosine Rules', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Solving \\( \\sin C = 0.919 \\) and giving only \\( C = 66.8^\\circ \\)</p><p><strong>✅ The correct idea:</strong> The ambiguous case has TWO answers. A weak answer stops at the acute value; a strong answer also gives \\( 180^\\circ - 66.8^\\circ = 113.2^\\circ \\) and checks both fit. This is the single most common lost mark on ambiguous-case questions.</p>", "question": "\\( \\sin C = 0.919 \\). What are the two possible values of \\( C \\)?", "options": ["\\( 66.8^\\circ \\) and \\( 113.2^\\circ \\)", "\\( 66.8^\\circ \\) only", "\\( 66.8^\\circ \\) and \\( 293.2^\\circ \\)", "\\( 23.2^\\circ \\) and \\( 156.8^\\circ \\)"]}'::jsonb, '{"answer": 0, "explain": "Acute \\( 66.8^\\circ \\); obtuse partner \\( 180^\\circ - 66.8^\\circ = 113.2^\\circ \\)."}'::jsonb),
('additional-maths:5-2-sine-and-cosine-rules:misc:91eee07c', 'additional-maths', 'additional-maths:5-2-sine-and-cosine-rules', '5.2 Sine and Cosine Rules', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Using the sine rule to find the third side when given two sides and the angle between them (SAS)</p><p><strong>✅ The correct idea:</strong> SAS gives no side paired with its opposite angle, so no sine-rule ratio can be formed. A strong answer recognises SAS and uses the cosine rule \\( a^2 = b^2 + c^2 - 2bc\\cos A \\).</p>", "question": "Two sides and the angle between them are known. Which rule finds the third side?", "options": ["The cosine rule", "The sine rule", "The area formula", "Pythagoras"]}'::jsonb, '{"answer": 0, "explain": "SAS → cosine rule; the sine rule needs a known side opposite a known angle."}'::jsonb),
('additional-maths:5-2-sine-and-cosine-rules:misc:cd7048df', 'additional-maths', 'additional-maths:5-2-sine-and-cosine-rules', '5.2 Sine and Cosine Rules', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Writing the cosine rule as \\( a^2 = b^2 + c^2 + 2bc\\cos A \\)</p><p><strong>✅ The correct idea:</strong> The final term is SUBTRACTED. A weak answer adds; a strong answer writes \\( a^2 = b^2 + c^2 - 2bc\\cos A \\), which for an obtuse angle (negative cosine) correctly makes \\( a \\) longer.</p>", "question": "Which cosine-rule form is correct?", "options": ["\\( a^2 = b^2 + c^2 - 2bc\\cos A \\)", "\\( a^2 = b^2 + c^2 + 2bc\\cos A \\)", "\\( a^2 = b^2 - c^2 - 2bc\\cos A \\)", "\\( a^2 = b^2 + c^2 - 2bc\\sin A \\)"]}'::jsonb, '{"answer": 0, "explain": "The cosine rule subtracts \\( 2bc\\cos A \\)."}'::jsonb),
('additional-maths:5-2-sine-and-cosine-rules:misc:e2a1c184', 'additional-maths', 'additional-maths:5-2-sine-and-cosine-rules', '5.2 Sine and Cosine Rules', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Using \\( \\dfrac{1}{2}ab\\sin C \\) with an angle that is NOT between sides a and b</p><p><strong>✅ The correct idea:</strong> The area formula needs the INCLUDED angle. A weak answer plugs in any angle; a strong answer first checks C is the angle between the two sides used, or finds the correct angle before substituting.</p>", "question": "In \\( \\dfrac{1}{2}ab\\sin C \\), which angle is C?", "options": ["The angle between sides a and b", "Any angle of the triangle", "The largest angle", "The angle opposite the longest side"]}'::jsonb, '{"answer": 0, "explain": "C is the included angle — the one between the two sides you multiply."}'::jsonb),
('additional-maths:5-2-sine-and-cosine-rules:misc:44c299a4', 'additional-maths', 'additional-maths:5-2-sine-and-cosine-rules', '5.2 Sine and Cosine Rules', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Finding the second ambiguous angle as \\( 360^\\circ - 66.8^\\circ = 293.2^\\circ \\)</p><p><strong>✅ The correct idea:</strong> The obtuse partner is \\( 180^\\circ - \\) the acute value, not \\( 360^\\circ - \\). A weak answer gives \\( 293.2^\\circ \\) (impossible in a triangle); a strong answer gives \\( 113.2^\\circ \\). Examiners noted candidates who subtracted from \\( 360^\\circ \\) produced angles over \\( 180^\\circ \\) without concern.</p>", "question": "The acute angle is \\( 66.8^\\circ \\). The obtuse partner is:", "options": ["\\( 180^\\circ - 66.8^\\circ = 113.2^\\circ \\)", "\\( 360^\\circ - 66.8^\\circ = 293.2^\\circ \\)", "\\( 90^\\circ - 66.8^\\circ = 23.2^\\circ \\)", "\\( 66.8^\\circ \\) doubled"]}'::jsonb, '{"answer": 0, "explain": "Supplementary angles share a sine, so the partner is \\( 180^\\circ - 66.8^\\circ = 113.2^\\circ \\)."}'::jsonb),
('additional-maths:5-2-sine-and-cosine-rules:tips:f39bd4af', 'additional-maths', 'additional-maths:5-2-sine-and-cosine-rules', '5.2 Sine and Cosine Rules', 'tips', 'mcq', 1, '{"readingTitle": "explain — Never lose the second angle (ambiguous case)", "reading": "<p><strong>0 marks (for the second value):</strong> stop at \\( C = 66.8^\\circ \\) when the question asks for two values.</p><p><strong>Partial:</strong> correct method and the acute value, but no obtuse partner.</p><p><strong>Full marks:</strong> \\( C = 66.8^\\circ \\) <em>and</em> \\( C = 180^\\circ - 66.8^\\circ = 113.2^\\circ \\). If the question says \"two possible values\", the calculator''s single answer is only half the work.</p>", "question": "A question asks for the two possible angles. You find \\( 66.8^\\circ \\). What next?", "options": ["Give \\( 180^\\circ - 66.8^\\circ = 113.2^\\circ \\) as the second value", "State \\( 66.8^\\circ \\) is the only answer", "Give \\( 360^\\circ - 66.8^\\circ = 293.2^\\circ \\) as the second value", "Double it to \\( 133.6^\\circ \\)"]}'::jsonb, '{"answer": 0, "explain": "The obtuse partner is the supplement, \\( 113.2^\\circ \\)."}'::jsonb),
('additional-maths:5-2-sine-and-cosine-rules:tips:985195d7', 'additional-maths', 'additional-maths:5-2-sine-and-cosine-rules', '5.2 Sine and Cosine Rules', 'tips', 'mcq', 1, '{"readingTitle": "tip — Pick the rule before you calculate", "reading": "<p>Before touching the calculator, name what you are given. <strong>SAS</strong> or <strong>SSS</strong> → cosine rule. <strong>ASA/AAS/SSA</strong> → sine rule. Using the sine rule on an SAS problem wastes time and scores nothing because no ratio can be completed. Examiners noted a few candidates who used the cosine rule where the sine rule was intended did far more work than the question was worth.</p>", "question": "You are given all three sides and want an angle. Which rule?", "options": ["Cosine rule, rearranged for the angle", "Sine rule, since three sides give enough to form a ratio", "Area formula", "Pythagoras"]}'::jsonb, '{"answer": 0, "explain": "SSS → cosine rule rearranged: \\( \\cos A = \\dfrac{b^2 + c^2 - a^2}{2bc} \\)."}'::jsonb),
('additional-maths:5-2-sine-and-cosine-rules:tips:0d1df7d4', 'additional-maths', 'additional-maths:5-2-sine-and-cosine-rules', '5.2 Sine and Cosine Rules', 'tips', 'mcq', 1, '{"readingTitle": "tip — Show the substitution (method marks)", "reading": "<p>For a sine-rule angle [typically 2 marks], examiners award an <strong>M</strong> for correct use of the rule and an <strong>M</strong> for rearranging to \\( \\sin C = \\dots \\), before the <strong>A</strong> marks for the values. Write \\( \\dfrac{\\sin C}{12} = \\dfrac{\\sin 50^\\circ}{10} \\) then \\( \\sin C = \\dfrac{12\\sin 50^\\circ}{10} \\) so a slip in the arithmetic costs one mark, not all of them.</p>", "question": "Why write the substituted sine rule before the final angle?", "options": ["To earn the method marks even if the final value slips", "To use more space", "It is not necessary", "To delay using the calculator until the very last step of working"]}'::jsonb, '{"answer": 0, "explain": "M marks reward the visible correct method (rule + rearrangement)."}'::jsonb),
('additional-maths:5-2-sine-and-cosine-rules:fib:1380cff5', 'additional-maths', 'additional-maths:5-2-sine-and-cosine-rules', '5.2 Sine and Cosine Rules', 'fib', 'fib', 1, '{"question": "In the sine rule \\( \\frac{a}{\\sin A} = \\frac{b}{\\sin B} \\), each side sits over the sine of the angle ___B1___ to it.", "blankOptions": {"B1": ["cosine", "included", "opposite", "SAS"]}}'::jsonb, '{"blanks": {"B1": "opposite"}}'::jsonb),
('additional-maths:5-2-sine-and-cosine-rules:fib:36a2d6af', 'additional-maths', 'additional-maths:5-2-sine-and-cosine-rules', '5.2 Sine and Cosine Rules', 'fib', 'fib', 2, '{"question": "You use the ___B1___ rule when you know two sides and the angle between them (SAS), and the ___B2___ rule when you know two angles and a side.", "blankOptions": {"B1": ["non-included", "opposite", "cosine", "2ab"], "B2": ["excluded", "opposite", "sine", "non-included"]}}'::jsonb, '{"blanks": {"B1": "cosine", "B2": "sine"}}'::jsonb),
