('additional-maths:5-3-trigonometric-identities:mcq:be11df5f', 'additional-maths', 'additional-maths:5-3-trigonometric-identities', '5.3 Trigonometric Identities', 'mcq', 'mcq', 1, '{"question": "Which statement is an identity (true for every \\( \\theta \\))?", "options": ["\\( \\cos^2\\theta - \\sin^2\\theta \\equiv 1 \\)", "\\( \\sin^2\\theta + \\cos^2\\theta \\equiv 1 \\)", "\\( \\sin\\theta = 0.5 \\)", "\\( \\cos\\theta = 1 \\)"]}'::jsonb, '{"answer": 1, "explain": "Only \\( \\sin^2\\theta + \\cos^2\\theta \\equiv 1 \\) holds for all \\( \\theta \\); \\( \\cos^2\\theta - \\sin^2\\theta \\) equals \\( \\cos2\\theta \\), not \\( 1 \\); the rest are equations true only for special angles."}'::jsonb),
